class Solution(object):
    def numberOfGoodPartitions(self, nums):
        """
        :type nums: List[int]
        :rtype: int
        """
        MOD = 10**9 + 7

        # Find last occurrence of each number
        last_pos = {}
        for i, num in enumerate(nums):
            last_pos[num] = i

        # Find minimum segments
        segments = 0
        max_reach = -1

        for i, num in enumerate(nums):
            max_reach = max(max_reach, last_pos[num])
            if i == max_reach:
                segments += 1

        # If all elements must be in one segment, answer is 0
        if segments == 0:
            return 0

        # Number of ways to partition m segments = 2^(m-1)
        # We can split after any of the first m-1 segments
        return pow(2, segments - 1, MOD)
